import React from 'react';
import { useNavigate, useLocation } from 'react-router-dom';

export default function SideBar() {
  const navigate = useNavigate();
  const location = useLocation();

  const navItems = [
    { name: 'Dashboard', path: '/dashboard' },
    { name: 'Service', path: '/service' },
    { name: 'Region', path: '/region' },
  ];

  const handleLogout = () => {
    localStorage.removeItem('isAuthenticated');
    localStorage.removeItem('user');
    navigate('/login');
  };

  return (
    <div className="w-64 min-h-screen bg-[#f5f6fa] flex flex-col justify-between border-r border-gray-200">
      <div className="p-6">
        <h2 className="text-xl font-semibold text-gray-800 mb-6">Menu</h2>
        <nav className="space-y-1">
          {navItems.map((item) => {
            const isActive = location.pathname === item.path;
            return (
              <div
                key={item.name}
                className={`px-4 py-2 rounded-l-lg cursor-pointer text-sm font-medium transition-colors ${
                  isActive
                    ? 'bg-white text-blue-600 border-l-4 border-blue-600'
                    : 'text-gray-600 hover:bg-gray-100'
                }`}
                onClick={() => navigate(item.path)}
              >
                {item.name}
              </div>
            );
          })}
        </nav>
      </div>

      <div className="p-6">
        <button
          onClick={handleLogout}
          className="w-full py-2 bg-red-500 text-white rounded-md hover:bg-red-600 transition-colors"
        >
          Logout
        </button>
      </div>
    </div>
  );
}
